SELECT  FROM file_task WHERE 1 = 1  AND del = #{del} 
        AND parent_id = #{parentId} 
        AND file_name LIKE CONCAT('%', #{fileName},
       '%') 
        AND file_path = #{filePath} 
        AND status = #{status} 
        AND md5 = #{md5} 
        AND
       user_id = #{userId}  ORDER BY gmt_created DESC LIMIT #{offset}, #{pageSize}

SELECT count(*) FROM file_task WHERE 1 = 1  AND del = #{del} 
        AND parent_id = #{parentId} 
        AND file_name LIKE CONCAT('%', #{fileName},
       '%') 
        AND file_path = #{filePath} 
        AND status = #{status} 
        AND md5 = #{md5} 
        AND
       user_id = #{userId}
